// ShaderLab Custom — Orbital
uniform float uTime,uScale,uLevel,uPmScale,uSpeed,uAmp,uSize;
attribute float aPhase;
varying float vBlink;
varying float vPhase;
void main(){
  vBlink=0.0;
  vPhase=aPhase;
  vec3 wpos=position*uPmScale;
  vec4 mvP=modelViewMatrix*vec4(wpos,1.0);
  gl_PointSize=0.0;
  vBlink = sin(uTime*(0.80+uLevel)*0.35+aPhase*6.2832)*0.24;
  {float _tb=sin(position.x*0.0050+uTime*1.80)*sin(position.y*0.0050+uTime*1.80*0.7)*2.0;wpos+=vec3(_tb,_tb*0.6,_tb*0.4);mvP=modelViewMatrix*vec4(wpos,1.0);}
  gl_PointSize=uScale*0.65*(1.1+vBlink*4.60)*100.0/-mvP.z;
  if(gl_PointSize<=0.0)
    gl_PointSize=uScale*uSize*(1.1+vBlink*4.0)*350.0/-mvP.z;
  gl_Position=projectionMatrix*mvP;
}

